using System;
using System.Numerics;

public static class SpanParser
{
    public static int SumCsvInts(ReadOnlySpan<char> csv)
    {
        if (csv.Length == 0) return 0;

        int sum = 0;
        bool isNegative = false;
        for (int i = 0; i < csv.Length; i++)
        {
            if (i == 0 && csv[i] == '-')
            {
                isNegative = true;
                continue;
            }

            if (!char.IsDigit(csv[i]))
            {
                if (i > 0)
                    throw new FormatException("Invalid CSV format.");

                return 0;
            }

            sum *= 10;
            sum += csv[i] - '0';
        }

        return isNegative ? -sum : sum;
    }
}

using System;

public static class SpanParser {
    public static int SumCsvInts(ReadOnlySpan<char> csv) {
        int sum = 0;
        bool isNegative = false;
        int currentDigit = 0;
        bool parsingNumber = false;

        foreach (char c in csv) {
            if (c == '-') {
                if (!parsingNumber || currentDigit != 0) return 0; // Invalid input
                isNegative = true;
                continue;
            }

            if (c >= '0' && c <= '9') {
                parsingNumber = true;
                currentDigit = currentDigit * 10 + (c - '0');
            } else if (c == ',') {
                if (!parsingNumber) return 0; // Invalid input
                sum += isNegative ? -currentDigit : currentDigit;
                currentDigit = 0;
                isNegative = false;
                parsingNumber = false;
            } else {
                return 0; // Invalid character in input
            }
        }

        if (parsingNumber) sum += isNegative ? -currentDigit : currentDigit;

        return sum;
    }
}
